INSERT INTO `app` VALUES (391758088325152768,'制作前端知识学习单页应用，采用卡片式布局展示HTML、CSS','https://rich-tams.oss-cn-beijing.aliyuncs.com/richcodeweaver/2026/03/20/44b9ce93e6eb403198a4726a708f1171.jpg','制作前端知识学习单页应用，采用卡片式布局展示HTML、CSS、JavaScript的示例和说明，包含代码高亮和实时预览功能。','single_html','d7lbpEaA','2026-03-20 16:10:45',99,390705603766513664,'2026-03-18 14:28:12','2026-03-18 14:07:46','2026-03-20 16:10:53',0),(391835539583537152,'创建一个现代风格计算器页面，支持基础数学运算和科学计算功能，','https://rich-tams.oss-cn-beijing.aliyuncs.com/logo.png','创建一个现代风格计算器页面，支持基础数学运算和科学计算功能，包含清晰的按钮布局和实时结果显示区域，支持明暗主题切换。','single_html','UJdBq9fh','2026-03-18 19:23:11',0,390705603766513664,'2026-03-18 19:15:32','2026-03-18 19:15:32','2026-03-18 19:23:26',1),(391839724840443904,'创建一个现代风格计算器页面，支持基础数学运算和科学计算功能，','https://rich-tams.oss-cn-beijing.aliyuncs.com/richcodeweaver/2026/03/20/70692a05057e48b287bea0a02edc42a2.jpg','创建一个现代风格计算器页面，支持基础数学运算和科学计算功能，包含清晰的按钮布局和实时结果。显示区域，支持明暗主题切换。','single_html','OlA8xmoo','2026-03-20 16:11:04',99,390705603766513664,'2026-03-18 19:35:27','2026-03-18 19:32:10','2026-03-20 16:11:08',0),(392814353788710912,'为一位个体互联网/IT从业者打造一个纯静态的开发者工具箱网站','https://rich-tams.oss-cn-beijing.aliyuncs.com/richcodeweaver/2026/03/21/939e7332bd69462390228352af8385e3.jpg','为一位个体互联网/IT从业者打造一个纯静态的开发者工具箱网站，采用 GitHub 风格配色（背景 #fff，文字与边框 #24292e），整体布局基于标签页切换导航，支持平滑过渡动效。网站包含以下五个真实可用的前端工具，均以独立卡片形式呈现，且全部功能在浏览器端完成（无需后端）：\n\n1. **JSON 格式化工具**：支持 JSON 字符串的格式化（美化）与压缩（最小化），实时校验语法并高亮错误；\n2. **Base64 编解码工具**：支持文本 ↔ Base64 的双向编解码，兼容 UTF-8 编码，输入变化时实时输出结果；\n3. **时间戳转换工具**：支持 Unix 时间戳（秒/毫秒）与标准日期时间（ISO 8601、YYYY-MM-DD HH:MM:SS 等常见格式）互转，可手动输入或点击“当前时间”快速填充；\n4. **正则表达式测试工具**：提供模式输入、测试字符串输入、标志选项（g/i/m）、匹配结果高亮显示及捕获组解析，支持实时匹配反馈；\n5. **颜色选择器工具**：纯前端实现的 HEX / RGB / HSL 三格式实时互转，含色块预览、复制颜色值功能，支持键盘输入与拾色交互（如 input[type=\"color\"] 基础增强）。\n\n所有工具均具备输入区与输出区的实时双向预览能力，标签页切换时有淡入/滑动等轻量动效，整体界面响应式设计，适配桌面与移动端浏览。数据处理全程运行于浏览器，不依赖任何外部 API 或服务端逻辑。','single_html','mX3g1AfL','2026-03-21 12:06:23',99,390705603766513664,'2026-03-21 12:25:49','2026-03-21 12:05:00','2026-03-21 12:25:49',0),(392815273259839488,'创建一个简单的日历小工具','https://rich-tams.oss-cn-beijing.aliyuncs.com/richcodeweaver/2026/03/21/368da6a7d4704609b1489fe37045fdd2.jpg','创建一个简单的日历小工具','single_html','Bo6rcSOx','2026-03-21 12:25:15',99,390705603766513664,'2026-03-21 12:25:50','2026-03-21 12:08:39','2026-03-21 12:25:49',0),(392817205487722496,'创建一个简单的日历小工具','https://rich-tams.oss-cn-beijing.aliyuncs.com/richcodeweaver/2026/03/21/3a06b27e6cc84fe594057a940226b18a.jpg','创建一个简单的日历小工具','single_html','2HYC91JP','2026-03-21 12:24:49',99,390705603766513664,'2026-03-21 12:25:51','2026-03-21 12:16:20','2026-03-21 13:40:41',1),(392819998923522048,'为一位个体互联网/IT从业者构建一个响应式、纯前端的开发者工','https://rich-tams.oss-cn-beijing.aliyuncs.com/logo.png','为一位个体互联网/IT从业者构建一个响应式、纯前端的开发者工具箱静态网站（Vue 3 + Composition API + Vite），采用暗色终端风格配色（主背景 #1e1e1e，强调色 #4ec9b0）。网站以标签页（Tabs）导航布局实现工具切换，具备平滑过渡动效（fade/slide）和输入输出区实时双向预览能力。\n\n功能模块包含以下5个完全可用的纯前端工具（不依赖后端API，全部逻辑在浏览器中运行）：\n- JSON格式化与校验（支持缩进、折叠、语法高亮、错误提示）\n- Base64编解码（支持文本/UTF-8字符串双向编解码，自动检测编码类型）\n- 时间戳转换（支持毫秒/秒级时间戳 ↔ 标准日期格式（ISO 8601、中文格式等），含本地时区与UTC切换）\n- 正则表达式测试器（支持输入正则模式与测试字符串，实时高亮匹配项、捕获组，并显示匹配结果、全局/忽略大小写等选项）\n- 十六进制颜色选择器（纯前端实现：HSV/RGB/HEX三模式联动拾色器，含色板、滑块、输入框、实时预览色块及对比文字）\n\n每个工具以独立卡片（Card）形式呈现，卡片内嵌对应UI组件，结构清晰、操作直观；所有表单控件均带输入验证与即时反馈。\n\n页面顶部集成一个自定义设计的简洁SVG工具LOGO（单色线性图标，体现“代码+工具箱”概念，适配暗色背景，可缩放不失真，内联SVG无外部依赖）。\n\n技术约束：  \n✅ 全静态部署（无服务端依赖）  \n✅ 数据持久化仅使用 localStorage（如保存用户常用设置、最近历史）  \n✅ 所有工具逻辑100%客户端执行，零网络请求  \n✅ 响应式设计，适配移动端触控与桌面端键盘操作（如JSON格式化支持Ctrl+Enter快捷格式化）  \n✅ Vue组件化结构，模块职责清晰，可维护性强  \n\n请生成完整、可直接运行的 Vue 3 项目代码（含 App.vue、各工具组件、Tab 切换逻辑、SVG LOGO 及样式体系）。','single_html',NULL,NULL,0,390705603766513664,'2026-03-21 12:27:26','2026-03-21 12:27:26','2026-03-21 13:11:01',1),(392826463130234880,'用VUE_PROJECT模式，为一位个体互联网/IT从业者创','https://rich-tams.oss-cn-beijing.aliyuncs.com/logo.png','用VUE_PROJECT模式，为一位个体互联网/IT从业者创建开发者工具箱静态网站。色系：暗色终端风(#1e1e1e+#4ec9b0)，布局：标签页切换。包含JSON格式化、Base64编解码、时间戳转换、正则测试、颜色选择器（纯前端实现）。每个工具以独立卡片展示，支持标签页切换。页面需有工具切换动效和输入输出实时预览。所有工具功能均需真实可用。\n记得给我AI生成一个LOGO，网上搜一搜资源。','ai_strategy',NULL,NULL,0,390705603766513664,'2026-03-21 12:53:07','2026-03-21 12:53:07','2026-03-21 13:11:05',1),(392837114271637504,'VUE项目模式。\n记得生成一个LOGO。\n\n为一位个体互联网','https://rich-tams.oss-cn-beijing.aliyuncs.com/richcodeweaver/2026/03/21/2a40c567d6534fa7aaaeaf3222e8f43f.jpg','VUE项目模式。\n记得生成一个LOGO。\n\n为一位个体互联网/IT从业者创建开发者工具箱静态网站。色系：暗色终端风(#1e1e1e+#4ec9b0)，布局：标签页切换。包含JSON格式化、Base64编解码、时间戳转换、正则测试、颜色选择器（纯前端实现）。每个工具以独立卡片展示，支持标签页切换。页面需有工具切换动效和输入输出实时预览。所有工具功能均需真实可用。','single_html','rCfCr6gI','2026-03-21 13:45:54',99,390705603766513664,'2026-03-21 13:40:39','2026-03-21 13:35:26','2026-03-21 15:31:43',1),(392842961378877440,'创建一个个体的活动宣传静态网站。色系：活力橙红(#e6510','https://rich-tams.oss-cn-beijing.aliyuncs.com/logo.png','创建一个个体的活动宣传静态网站。色系：活力橙红(#e65100+#fff3e0)，布局：全屏模块滚动。包含活动主题全屏Banner、活动倒计时器（纯JS实现实时倒计时）、活动日程时间表、嘉宾/组织者介绍卡片、往期活动数据回顾（参与人数等数字动效）、报名表单（仅UI无后端）。请为活动设计一个主题 LOGO。页面需有倒计时翻牌和模块渐入动效。所有内容使用真实可信的活动场景文本。创建基于VUE的项目。','vue_project',NULL,NULL,0,390705603766513664,'2026-03-21 13:58:40','2026-03-21 13:58:40','2026-03-21 14:12:13',1),(392846708670763008,'创建一个个体的活动“春游”宣传静态网站。色系：活力橙红(#e','https://rich-tams.oss-cn-beijing.aliyuncs.com/richcodeweaver/2026/03/21/8a3bac5919cd42588c951dc6142db5b1.jpg','创建一个个体的活动“春游”宣传静态网站。色系：活力橙红(#e65100+#fff3e0)，布局：全屏模块滚动。包含活动主题全屏Banner、活动倒计时器（纯JS实现实时倒计时）、活动日程时间表、嘉宾/组织者介绍卡片、往期活动数据回顾（参与人数等数字动效）、报名表单（仅UI无后端）。请为活动设计一个主题 LOGO。页面需有倒计时翻牌和模块渐入动效。所有内容使用真实可信的活动场景文本。创建基于VUE的项目。数据模拟即可。','vue_project','YbR8rhC7','2026-03-21 14:24:13',0,390705603766513664,'2026-03-21 14:13:34','2026-03-21 14:13:34','2026-03-21 15:31:41',1),(392855247078309888,'创建一个个体的活动“春游”宣传静态网站。色系：活力橙红(#e','https://rich-tams.oss-cn-beijing.aliyuncs.com/logo.png','创建一个个体的活动“春游”宣传静态网站。色系：活力橙红(#e65100+#fff3e0)，布局：全屏模块滚动。包含活动主题全屏Banner、活动倒计时器（纯JS实现实时倒计时）、活动日程时间表、嘉宾/组织者介绍卡片、往期活动数据回顾（参与人数等数字动效）、报名表单（仅UI无后端）。请为活动设计一个主题 LOGO。页面需有倒计时翻牌和模块渐入动效。所有内容使用真实可信的活动场景文本。创建基于VUE的项目。数据模拟即可。','vue_project',NULL,NULL,0,390705603766513664,'2026-03-21 14:47:29','2026-03-21 14:47:29','2026-03-21 15:31:35',1),(392865109162074112,'计算器网站','https://rich-tams.oss-cn-beijing.aliyuncs.com/richcodeweaver/2026/03/21/97eb7b8280004a478196a584c766325b.jpg','创建一个简单的计算器网站。\n不用设计LOGO。\n创建基于VUE的项目。','vue_project','wmhCdEOU','2026-03-21 15:31:53',99,390705603766513664,'2026-03-21 16:22:45','2026-03-21 15:26:41','2026-03-21 16:22:44',0),(392879699639934976,'创建一个个体的产品发布静态网站。色系：科技蓝(#0d47a1','https://rich-tams.oss-cn-beijing.aliyuncs.com/logo.png','创建一个个体的产品发布静态网站。色系：科技蓝(#0d47a1+#e3f2fd)，布局：单页滚动。包含产品Hero大图+标语、核心功能亮点卡片（3-5个特性）、产品演示视频占位区、技术规格参数表、用户评价轮播、下载/购买CTA按钮。请为产品设计一个SVG LOGO。页面需有滚动渐入和功能卡片动效。所有内容使用真实可信的产品场景文本。\n发布内容为一款杯子。','single_html',NULL,NULL,0,390705603766513664,'2026-03-21 16:24:39','2026-03-21 16:24:39','2026-03-21 16:26:07',0);
