x;\n            cursor: pointer;\n            transition: background 0.3s ease;\n        }\n\n        .calendar-day:hover {\n            background-color: #e0e0e0;\n        }\n\n        .calendar-day.today {\n            background-color: var(--primary-color);\n            color: white;\n        }\n\n        @media (max-width: 768px) {\n            .calendar-header h2 {\n                font-size: 1.2rem;\n            }\n        }\n    </style>\n</head>\n<body>\n    <div class=\"calendar-container\">\n        <div class=\"calendar-header\">\n            <button id=\"prevMonth\">❮</button>\n            <h2 id=\"currentMonthYear\"></h2>\n            <button id=\"nextMonth\">❯</button>\n        </div>\n        <div class=\"calendar-weekdays\">\n            <div>日</div>\n            <div>一</div>\n            <div>二</div>\n            <div>三</div>\n            <div>四</div>\n            <div>五</div>\n            <div>六</div>\n        </div>\n        <div class=\"calendar-days\" id=\"calendarDays\"></div>\n    </div>\n\n    <script>\n        const calendarDays = document.getElementById(\'calendarDays\');\n        const currentMonthYear = document.getElementById(\'currentMonthYear\');\n        const prevMonthBtn = document.getElementById(\'prevMonth\');\n        const nextMonthBtn = document.getElementById(\'nextMonth\');\n\n        let currentDate = new Date();\n\n        function renderCalendar() {\n            const year = currentDate.getFullYear();\n            const month = currentDate.getMonth();\n\n            const firstDay = new Date(year, month, 1);\n            const lastDay = new Date(year, month + 1, 0);\n\n            const daysInMonth = lastDay.getDate();\n            const startDay = firstDay.getDay();\n\n            // 清空之前的日历内容\n            calendarDays.innerHTML = \'\';\n\n            // 填充空白的日期（前一个月）\n            for (let i = 0; i < startDay; i++) {\n                const dayDiv = document.createElement(\'div\');\n                dayDiv.classList.add(\'calendar-day\');\n                calendarDays.appendChild(dayDiv);\n            }\n\n            // 填充当前月的日期\n            for (let day = 1; day <= daysInMonth; day++) {\n                const dayDiv = document.createElement(\'div\');\n                dayDiv.classList.add(\'calendar-day\');\n                dayDiv.textContent = day;\n\n                const today = new Date();\n                if (year === today.getFullYear() && month === today.getMonth() && day === today.getDate()) {\n                    dayDiv.classList.add(\'today\');\n                }\n\n                calendarDays.appendChild(dayDiv);\n            }\n\n            currentMonthYear.textContent = `${year}年${month + 1}月`;\n        }\n\n        prevMonthBtn.addEventListener(\'click\', () => {\n            currentDate.setMonth(currentDate.getMonth() - 1);\n            renderCalendar();\n        });\n\n        nextMonthBtn.addEventListener(\'click\', () => {\n            currentDate.setMonth(currentDate.getMonth() + 1);\n            renderCalendar();\n        });\n\n        // 初始化日历\n        renderCalendar();\n    </script>\n</body>\n</html>\n```\n\n<!-- NODE_START:ai_code_generator_type_strategy -->\n\n### ✅ 代码生成类型策略已完成\n\n<div class=\'node-result\'>\n\n**🎯 代码类型策略节点**\n\n\n\n</div>\n\n<!-- NODE_END:ai_code_generator_type_strategy -->\n\n\n\n<!-- NODE_START:code_generator -->\n\n### ✅ AI 代码生成已完成\n\n<div class=\'node-result\'>\n\n**💻 AI 代码生成节点**\n\n- ✓ 生成完成：代码已输出\n- ✓ 输出路径：`E:\\AAA_idea_java\\RichCodeWeaver/appCode/code_output/single_html_392817205487722496`\n- ✓ 下一步：等待 AI 代码质量审查\n\n> 🔍 正在启动代码审查流程...\n\n\n</div>\n\n<!-- NODE_END:code_generator -->\n\n\n\n<!-- NODE_START:ai_code_reviewer -->\n\n### ✅ 代码审查\n\n<div class=\'node-result\'>\n\n**🔍 代码审查节点**\n\n- ✅ **审查通过**：代码质量符合标准\n- ✓ 代码规范：符合最佳实践\n- ✓ 功能完整：满足需求描述\n\n\n</div>\n\n<!-- NODE_END:ai_code_reviewer -->\n\n\n\n<!-- NODE_START:__END__ -->\n\n### ✅ 代码审查\n\n<div class=\'node-result\'>\n\n**⚙️ 工作流初始化**\n\n- ✓ 工作流上下文已创建\n- ✓ 执行参数已配置完成\n- ✓ 准备开始执行各节点任务