 ease;\n    }\n\n    nav button:hover {\n      color: var(--accent-color);\n    }\n\n    main {\n      margin-top: 30px;\n    }\n\n    .tabs {\n      display: flex;\n      gap: 10px;\n      overflow-x: auto;\n      padding-bottom: 10px;\n      border-bottom: 1px solid var(--input-border);\n    }\n\n    .tab-button {\n      padding: 10px 15px;\n      border: none;\n      background: none;\n      color: var(--text-color);\n      cursor: pointer;\n      font-weight: bold;\n      transition: color 0.3s ease;\n    }\n\n    .tab-button.active {\n      color: var(--accent-color);\n      border-bottom: 2px solid var(--accent-color);\n    }\n\n    .tab-content {\n      display: none;\n      padding: 20px;\n      background-color: var(--card-bg);\n      border-radius: 8px;\n    }\n\n    .tab-content.active {\n      display: block;\n    }\n\n    .card {\n      background-color: var(--card-bg);\n      border: 1px solid var(--input-border);\n      border-radius: 8px;\n      padding: 20px;\n      margin-bottom: 20px;\n    }\n\n    .card h2 {\n      margin-bottom: 10px;\n    }\n\n    .form-group {\n      margin-bottom: 15px;\n    }\n\n    label {\n      display: block;\n      margin-bottom: 5px;\n      font-weight: bold;\n    }\n\n    input, textarea, select {\n      width: 100%;\n      padding: 10px;\n      border: 1px solid var(--input-border);\n      background-color: var(--card-bg);\n      color: var(--text-color);\n      border-radius: 4px;\n      transition: border-color 0.3s ease;\n    }\n\n    input:focus, textarea:focus, select:focus {\n      border-color: var(--accent-color);\n      outline: none;\n    }\n\n    .error-message {\n      color: var(--error-color);\n      font-size: 14px;\n      margin-top: 5px;\n    }\n\n    .output {\n      white-space: pre-wrap;\n      background-color: #2d2d2d;\n      padding: 10px;\n      border-radius: 4px;\n      min-height: 100px;\n      overflow-x: auto;\n    }\n\n    .color-picker {\n      display: flex;\n      flex-direction: column;\n      gap: 10px;\n    }\n\n    .color-preview {\n      width: 100px;\n      height: 100px;\n      border: 1px solid #ccc;\n      display: flex;\n      align-items: center;\n      justify-content: center;\n      font-size: 14px;\n      color: #fff;\n      text-align: center;\n    }\n\n    @media (max-width: 768px) {\n      nav {\n        flex-direction: column;\n        gap: 10px;\n      }\n    }\n  </style>\n</head>\n<body>\n  <div id=\"app\">\n    <header>\n      <div class=\"logo\">\n        <svg viewBox=\"0 0 40 40\" xmlns=\"http://www.w3.org/2000/svg\">\n          <path d=\"M10 10h20v20H10z\" fill=\"none\" stroke=\"#ffffff\" stroke-width=\"2\"/>\n          <path d=\"M15 15h10v10H15z\" fill=\"none\" stroke=\"#ffffff\" stroke-width=\"2\"/>\n          <path d=\"M10 10l20 20\" stroke=\"#ffffff\" stroke-width=\"2\"/>\n        </svg>\n      </div>\n      <nav>\n        <button class=\"tab-button active\" data-tab=\"json\">JSON 格式化</button>\n        <button class=\"tab-button\" data-tab=\"base64\">Base64 编解码</button>\n        <button class=\"tab-button\" data-tab=\"timestamp\">时间戳转换</button>\n        <button class=\"tab-button\" data-tab=\"regex\">正则测试器</button>\n        <button class=\"tab-button\" data-tab=\"color\">颜色选择器</button>\n      </nav>\n    </header>\n\n    <main>\n      <div class=\"tabs\">\n        <button class=\"tab-button active\" data-tab=\"json\">JSON 格式化</button>\n        <button class=\"tab-button\" data-tab=\"base64\">Base64 编解码</button>\n        <button class=\"tab-button\" data-tab=\"timestamp\">时间戳转换</button>\n        <button class=\"tab-button\" data-tab=\"regex\">正则测试器</button>\n        <button class=\"tab-button\" data-tab=\"color\">颜色选择器</button>\n      </div>\n\n      <div class=\"tab-content active\" id=\"json\">\n        <div class=\"card\">\n          <h2>JSON 格式化与校验</h2>\n          <div class=\"form-group\">\n            <label for=\"jsonInput\">输入 JSON 内容</label>\n            <textarea id=\"jsonInput\" rows=\"10\"></textarea>\n            <div class=\"error-message\" id=\"jsonError\"></div>\n          </div>\n          <div class=\"form-group\">\n            <label for=\"jsonOutput\">输出格式化 JSON</label>\n            <textarea id=\"jsonOutput\" rows=\"10\" readonly></textarea>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"tab-content\" id=\"base64\">\n        <div class=\"card\">\n          <h2>Base64 编解码</h2>\n          <div class=\"form-group\">\n            <label for=\"base64Input\">输入文本或 Base64 字符串</label>\n            <textarea id=\"base64Input\" rows=\"5\"></textarea>\n            <div class=\"error-message\" id=\"base64Error\"></div>\n          </div>\n          <div class=\"form-group\">\n            <label for=\"base64Output\">编码/解码结果</label>\n            <textarea id=\"base64Output\" rows=\"5\" readonly></textarea>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"tab-content\" id=\"timestamp\">\n        <div class=\"card\">\n          <h2>时间戳转换</h2>\n          <div class=\"form-group\">\n            <label for=\"timestampInput\">输入时间戳（毫秒/秒）</label>\n            <input type=\"number\" id=\"timestampInput\" />\n            <div class=\"error-message\" id=\"timestampError\"></div>\n          </div>\n          <div class=\"form-group\">\n            <label for=\"timestampOutput\">转换后的时间</label>\n            <input type=\"text\" id=\"timestampOutput\" readonly />\n          </div>\n          <div class=\"form-group\">\n            <label for=\"timezoneSelect\">时区</label>\n            <select id=\"timezoneSelect\">\n              <option value=\"local\">本地时区</option>\n              <option value=\"utc\">UTC 时区</option>\n            </select>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"tab-content\" id=\"regex\">\n        <div class=\"card\">\n          <h2>正则表达式测试器</h2>\n          <div class=\"form-group\">\n            <label for=\"regexPattern\">正则表达式模式</label>\n            <input type=\"text\" id=\"regexPattern\" />\n          </div>\n          <div class=\"form-group\">\n            <label for=\"regexTestString\">测试字符串</label>\n            <input type=\"text\" id=\"regexTestString\" />\n          </div>\n          <div class=\"form-group\">\n            <label for=\"regexFlags\">标志</label>\n            <select id=\"regexFlags\">\n              <option value=\"\">无</option>\n              <option value=\"g\">全局匹配</option>\n              <option value=\"i\">忽略大小写</option>\n              <option value=\"m\">多行模式</option>\n              <option value=\"s\">单行模式</option>\n              <option value=\"u\">Unicode 模式</option>\n              <option value=\"y\">粘滞模式</option>\n            </select>\n          </div>\n          <div class=\"form-group\">\n            <label for=\"regexOutput\">匹配结果</label>\n            <textarea id=\"regexOutput\" rows=\"5\" readonly></textarea>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"tab-content\" id=\"color\">\n        <div class=\"card\">\n          <h2>十六进制颜色选择器</h2>\n          <div class=\"color-picker\">\n            <div class=\"form-group\">\n              <label for=\"hexInput\">HEX 颜色值</label>\n              <input type=\"text\" id=\"hexInput\" placeholder=\"#000000\" />\n            </div>\n            <div class=\"form-group\">\n              <label for=\"rgbInput\">RGB 值</label>\n              <input type=\"text\" id=\"rgbInput\" placeholder=\"rgb(0, 0, 0)\" />\n            </div>\n            <div class=\"form-group\">\n              <label for=\"hsvInput\">HSV 值</label>\n              <input type=\"text\" id=\"hsvInput\" placeholder=\"hsv(0, 0%, 0%)\" />\n            </div>\n            <div class=\"form-group\">\n              <label for=\"colorPreview\">预览颜色</label>\n              <div class=\"color-preview\" id=\"colorPreview\">预览区域</div>\n            </div>\n          </div>\n        </div>\n      </div>\n    </main>\n  </div>\n\n  <script>\n    // Tab 切换逻辑\n    const tabs = document.querySelectorAll(\'.tab-button\');\n    const tabContents = document.querySelectorAll(\'.tab-content\');\n\n    tabs.forEach(tab => {\n      tab.addEventListener(\'click\', () => {\n        const targetTab = tab.dataset.tab;\n\n        tabs.forEach(t => t.classList.remove(\'active\'));\n        tabContents.forEach(tc => tc.classList.remove(\'active\'));\n\n        tab.classList.add(\'active\');\n        document.getElementById(targetTab).classList.add(\'active\');\n      });\n    });\n\n    // JSON 格式化与校验\n    const jsonInput = document.getElementById(\'jsonInput\');\n    const jsonOutput = document.getElementById(\'jsonOutput\');\n    const jsonError = document.getElementById(\'jsonError\');\n\n    jsonInput.addEventListener(\'input\', () => {\n      try {\n        const parsed = JSON.parse(jsonInput.value);\n        jsonOutput.value = JSON.stringify(parsed, null, 2);\n        jsonError.textContent = \'\';\n      } catch (e) {\n        jsonOutput.value = \'\';\n        jsonError.textContent = \'无效的 JSON 格式: \' + e.message;\n      }\n    });\n\n    // Base64 编解码\n    const base64Input = document.getElementById(\'base64Input\');\n    const base64Output = document.getElementById(\'base64Output\');\n    const base64Error = document.getElementById(\'base64Error\');\n\n    base64Input.addEventListener(\'input\', () => {\n      try {\n        const inputValue = base64Input.value.trim();\n        if (/^[A-Za-z0-9+/]+={0,2}$/.test(inputValue)) {\n          // 解码 Base64\n          const decoded = atob(inputValue);\n          base64Output.value = decoded;\n          base64Error.textContent = \'\';\n        } else {\n          // 编码为 Base64\n          const encoded = btoa(inputValue);\n          base64Output.value = encoded;\n          base64Error.textContent = \'\';\n        }\n      } catch (e) {\n        base64Output.value = \'\';\n        base64Error.textContent = \'Base64 编解码错误: \' + e.message;\n      }\n    });\n\n    // 时间戳转换\n    const timestampInput = document.getElementById(\'timestampInput\');\n    const timestampOutput = document.getElementById(\'timestampOutput\');\n    const timezoneSelect = document.getElementById(\'timezoneSelect\');\n\n    timestampInput.addEventListener(\'input\', () => {\n      const value = timestampInput.value.trim();\n      if (!value) {\n        timestampOutput.value = \'\';\n        return;\n      }\n\n      let timestamp = parseInt(value);\n      if (isNaN(timestamp)) {\n        timestampOutput.value = \'无效的时间戳\';\n        return;\n      }\n\n      const date = new Date(timestamp);\n      const timezone = timezoneSelect.value === \'local\' ? \'local\' : \'UTC\';\n\n      const options = {\n        timeZone: timezone,\n        year: \'numeric\',\n        month: \'2-digit\',\n        day: \'2-digit\',\n        hour: \'2-digit\',\n        minute: \'2-digit\',\n        second: \'2-digit\'\n      };\n\n      const formattedDate = date.toLocaleString(\'zh-CN\', options);\n      timestampOutput.value = formattedDate;\n    });\n\n    // 正则表达式测试器\n    const regexPattern = document.getElementById(\'regexPattern\');\n    const regexTestString = document.getElementById(\'regexTestString\');\n    const regexFlags = document.getElementById(\'regexFlags\');\n    const regexOutput = document.getElementById(\'regexOutput\');\n\n    function testRegex() {\n      const pattern = regexPattern.value;\n      const testString = regexTestString.value;\n      const flags = regexFlags.value;\n\n      try {\n        const regex = new RegExp(pattern, flags);\n        const matches = [];\n        let match;\n\n        while ((match = regex.exec(testString)) !== null) {\n          matches.push({\n            value: match[0],\n            start: match.index,\n            end: match.index + match[0].length,\n            groups: match.groups || {}\n          });\n        }\n\n        regexOutput.value = matches.length > 0\n          ? `匹配到 ${matches.length} 个结果:\\n${matches.map((m, i) => \n              `匹配项 ${i + 1}: ${m.value}\\n位置: ${m.start}-${m.end}`\n            ).join(\'\\n\')}\n          ` : \'未找到匹配项\';\n      } catch (e) {\n        regexOutput.value = \'正则表达式错误: \' + e.message;\n      }\n    }\n\n    regexPattern.addEventListener(\'input\', testRegex);\n    regexTestString.addEventListener(\'input\', testRegex);\n    regexFlags.addEventListener(\'change\', testRegex);\n\n    // 十六进制颜色选择器\n    const hexInput = document.getElementById(\'hexInput\');\n    const rgbInput = document.getElementById(\'rgbInput\');\n    const hsvInput = document.getElementById(\'hsvInput\');\n    const colorPreview = document.getElementById(\'colorPreview\');\n\n    function updateColorPreview(hex) {\n      const hexColor = hex.startsWith(\'#\') ? hex : \'#\' + hex;\n      colorPreview.style.backgroundColor = hexColor;\n      colorPreview.textContent = hexColor;\n\n      const rgb = hexToRgb(hexColor);\n      if (rgb) {\n        rgbInput.value = `rgb(${rgb.r}, ${rgb.g}, ${rgb.b})`;\n        const hsv = rgbToHsv(rgb.r, rgb.g, rgb.b);\n        hsvInput.value = `hsv(${hsv.h}, ${hsv.s}%, ${hsv.v}%)`;\n      }\n    }\n\n    function hexToRgb(hex) {\n      const result = /^#?([a-f\\d]{2})([a-f\\d]{2})([a-f\\d]{2})$/i.exec(hex);\n      return result ? {\n        r: parseInt(result[1], 16),\n        g: parseInt(result[2], 16),\n        b: parseInt(result[3], 16)\n      } : null;\n    }\n\n    function rgbToHsv(r, g, b) {\n      r /= 255, g /= 255, b /= 255;\n      let h, s, v = Math.max(r, g, b), min = Math.min(r, g, b);\n      let d = v - min;\n      s = v === 0 ? 0 : d / v;\n      if (v === min) {\n        h = 0;\n      } else {\n        switch (v) {\n          case r: h = (g - b) / d + (g < b ? 6 : 0); break;\n          case g: h = (b - r) / d + 2; break;\n          case b: h = (r - g) / d + 4; break;\n        }\n        h /= 6;\n      }\n      return { h: Math.round(h * 360), s: Math.round(s * 100), v: Math.round(v * 100) };\n    }\n\n    hexInput.addEventListener(\'input\', () => {\n      const hex = hexInput.value.trim();\n      if (/^#?[0-9A-Fa-f]{6}$/.test(hex)) {\n        updateColorPreview(hex);\n      }\n    });\n\n    rgbInput.addEventListener(\'input\', () => {\n      const rgb = rgbInput.value.match(/^rgb\\((\\d+),\\s*(\\d+),\\s*(\\d+)\\)$/i);\n      if (rgb) {\n        const hex = rgbToHex(parseInt(rgb[1]), parseInt(rgb[2]), parseInt(rgb[3]));\n        updateColorPreview(hex);\n      }\n    });\n\n    hsvInput.addEventListener(\'input\', () => {\n      const hsv = hsvInput.value.match(/^hsv\\((\\d+),\\s*(\\d+)%,\\s*(\\d+)%\\)$/i);\n      if (hsv) {\n        const rgb = hsvToRgb(parseInt(hsv[1]), parseInt(hsv[2]), parseInt(hsv[3]));\n        const hex = rgbToHex(rgb.r, rgb.g, rgb.b);\n        updateColorPreview(hex);\n      }\n    });\n\n    function rgbToHex(r, g, b) {\n      return \"#\" + [r, g, b].map(x => x.toString(16).padStart(2, \"0\")).join(\"\");\n    }\n\n    function hsvToRgb(h, s, v) {\n      s /= 100;\n      v /= 100;\n      let c = v * s;\n      let x = c * (1 - Math.abs((h / 60) % 2 - 1));\n      let m = v - c;\n      let r, g, b;\n\n      if (h < 60) {\n        r = c; g = x; b = 0;\n      } else if (h < 120) {\n        r = x; g = c; b = 0;\n      } else if (h < 180) {\n        r = 0; g = c; b = x;\n      } else if (h < 240) {\n        r = 0; g = x; b = c;\n      } else if (h < 300) {\n        r = x; g = 0; b = c;\n      } else {\n        r = c; g = 0; b = x;\n      }\n\n      return {\n        r: Math.round((r + m) * 255),\n        g: Math.round((g + m) * 255),\n        b: Math.round((b + m) * 255)\n      };\n    }\n  </script>\n</body>\n</html>\n```\n\n<!-- NODE_START:ai_code_generator_type_strategy -->\n\n### ✅ 代码生成类型策略已完成\n\n<div class=\'node-result\'>\n\n**🎯 代码类型策略节点**\n\n\n\n</div>\n\n<!-- NODE_END:ai_code_generator_type_strategy -->\n\n\n\n<!-- NODE_START:code_generator -->\n\n### ✅ AI 代码生成已完成\n\n<div class=\'node-result\'>\n\n**💻 AI 代码生成节点**\n\n- ✓ 生成完成：代码已输出\n- ✓ 输出路径：`E:\\AAA_idea_java\\RichCodeWeaver/appCode/code_output/single_html_392819998923522048`\