olor: #ffffff;\n      --input-bg: #2a2a2a;\n      --input-border: #4ec9b0;\n      --success-color: #4ec9b0;\n      --error-color: #f44336;\n      --font-family: \'Fira Code\', monospace;\n    }\n\n    * {\n      box-sizing: border-box;\n      margin: 0;\n      padding: 0;\n      font-family: var(--font-family);\n    }\n\n    body {\n      background-color: var(--bg-color);\n      color: var(--text-color);\n      display: flex;\n      flex-direction: column;\n      min-height: 100vh;\n      transition: background-color 0.3s ease;\n    }\n\n    header {\n      background-color: var(--bg-color);\n      padding: 1rem;\n      display: flex;\n      align-items: center;\n      justify-content: space-between;\n      position: sticky;\n      top: 0;\n      z-index: 1000;\n    }\n\n    .logo {\n      display: flex;\n      align-items: center;\n      gap: 0.5rem;\n    }\n\n    .logo svg {\n      width: 40px;\n      height: 40px;\n    }\n\n    .logo span {\n      font-size: 1.5rem;\n      font-weight: bold;\n    }\n\n    nav {\n      display: flex;\n      gap: 1rem;\n    }\n\n    nav a {\n      text-decoration: none;\n      color: var(--text-color);\n      padding: 0.5rem 1rem;\n      border-radius: 4px;\n      transition: background-color 0.3s ease;\n    }\n\n    nav a:hover {\n      background-color: var(--primary-color);\n      color: var(--bg-color);\n    }\n\n    main {\n      flex: 1;\n      padding: 2rem;\n      display: flex;\n      flex-direction: column;\n      gap: 2rem;\n    }\n\n    .tabs {\n      display: flex;\n      overflow-x: auto;\n      border-bottom: 2px solid var(--primary-color);\n      padding-bottom: 0.5rem;\n    }\n\n    .tab-button {\n      padding: 0.75rem 1.5rem;\n      cursor: pointer;\n      border: none;\n      background: none;\n      color: var(--text-color);\n      font-weight: bold;\n      transition: all 0.3s ease;\n    }\n\n    .tab-button.active {\n      border-bottom: 2px solid var(--primary-color);\n      color: var(--primary-color);\n    }\n\n    .tab-content {\n      display: none;\n      padding: 1rem;\n      background-color: var(--secondary-color);\n      border-radius: 8px;\n      transition: opacity 0.3s ease, transform 0.3s ease;\n    }\n\n    .tab-content.active {\n      display: block;\n      opacity: 1;\n      transform: translateX(0);\n    }\n\n    .tool-card {\n      background-color: var(--input-bg);\n      border: 1px solid var(--input-border);\n      border-radius: 8px;\n      padding: 1rem;\n      margin-bottom: 1rem;\n      transition: transform 0.3s ease;\n    }\n\n    .tool-card:hover {\n      transform: scale(1.02);\n    }\n\n    .tool-title {\n      font-size: 1.2rem;\n      margin-bottom: 0.5rem;\n      color: var(--primary-color);\n    }\n\n    .tool-description {\n      font-size: 0.9rem;\n      color: #ccc;\n      margin-bottom: 1rem;\n    }\n\n    .input-group {\n      margin-bottom: 1rem;\n    }\n\n    textarea, input[type=\"text\"] {\n      width: 100%;\n      padding: 0.5rem;\n      background-color: var(--input-bg);\n      color: var(--text-color);\n      border: 1px solid var(--input-border);\n      border-radius: 4px;\n      font-family: var(--font-family);\n      resize: vertical;\n      min-height: 100px;\n    }\n\n    button {\n      background-color: var(--primary-color);\n      color: var(--bg-color);\n      border: none;\n      padding: 0.5rem 1rem;\n      border-radius: 4px;\n      cursor: pointer;\n      transition: background-color 0.3s ease;\n    }\n\n    button:hover {\n      background-color: #3aa08d;\n    }\n\n    .output {\n      background-color: var(--input-bg);\n      padding: 1rem;\n      border: 1px solid var(--input-border);\n      border-radius: 4px;\n      white-space: pre-wrap;\n      font-family: var(--font-family);\n    }\n\n    .output.error {\n      border-color: var(--error-color);\n      color: var(--error-color);\n    }\n\n    footer {\n      background-color: var(--bg-color);\n      padding: 1rem;\n      text-align: center;\n      font-size: 0.9rem;\n      color: #aaa;\n    }\n\n    @media (max-width: 768px) {\n      header {\n        flex-direction: column;\n        align-items: flex-start;\n      }\n\n      nav {\n        flex-direction: column;\n        gap: 0.5rem;\n      }\n    }\n  </style>\n</head>\n<body>\n  <header>\n    <div class=\"logo\">\n      <!-- Logo SVG -->\n      <svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 100 100\">\n        <rect x=\"0\" y=\"0\" width=\"100\" height=\"100\" fill=\"#1e1e1e\"/>\n        <text x=\"50%\" y=\"50%\" text-anchor=\"middle\" dominant-baseline=\"middle\" fill=\"#4ec9b0\" font-family=\"Fira Code\" font-size=\"36\">D</text>\n        <text x=\"50%\" y=\"50%\" text-anchor=\"middle\" dominant-baseline=\"middle\" fill=\"#4ec9b0\" font-family=\"Fira Code\" font-size=\"36\" dx=\"20\">K</text>\n        <text x=\"50%\" y=\"50%\" text-anchor=\"middle\" dominant-baseline=\"middle\" fill=\"#4ec9b0\" font-family=\"Fira Code\" font-size=\"36\" dx=\"40\">T</text>\n      </svg>\n      <span>DevKit Terminal</span>\n    </div>\n    <nav>\n      <a href=\"#\" class=\"tab-button active\" data-tab=\"json\">JSON 格式化</a>\n      <a href=\"#\" class=\"tab-button\" data-tab=\"base64\">Base64 编解码</a>\n      <a href=\"#\" class=\"tab-button\" data-tab=\"timestamp\">时间戳转换</a>\n      <a href=\"#\" class=\"tab-button\" data-tab=\"regex\">正则测试</a>\n      <a href=\"#\" class=\"tab-button\" data-tab=\"color\">颜色选择器</a>\n    </nav>\n  </header>\n\n  <main>\n    <div class=\"tabs\">\n      <button class=\"tab-button active\" data-tab=\"json\">JSON 格式化</button>\n      <button class=\"tab-button\" data-tab=\"base64\">Base64 编解码</button>\n      <button class=\"tab-button\" data-tab=\"timestamp\">时间戳转换</button>\n      <button class=\"tab-button\" data-tab=\"regex\">正则测试</button>\n      <button class=\"tab-button\" data-tab=\"color\">颜色选择器</button>\n    </div>\n\n    <section class=\"tab-content active\" id=\"json\">\n      <div class=\"tool-card\">\n        <h2 class=\"tool-title\">JSON 格式化</h2>\n        <p class=\"tool-description\">实时美化、校验、折叠/展开，支持超大 JSON（>2MB）</p>\n        <div class=\"input-group\">\n          <textarea id=\"json-input\" placeholder=\"粘贴压缩 JSON → 自动格式化\"></textarea>\n        </div>\n        <button onclick=\"formatJson()\">格式化 JSON</button>\n        <div class=\"output\" id=\"json-output\"></div>\n      </div>\n    </section>\n\n    <section class=\"tab-content\" id=\"base64\">\n      <div class=\"tool-card\">\n        <h2 class=\"tool-title\">Base64 编解码</h2>\n        <p class=\"tool-description\">文本 ↔ Base64 双向转换；支持文件拖拽编码（图片/PDF）</p>\n        <div class=\"input-group\">\n          <textarea id=\"base64-input\" placeholder=\"输入文本或拖入文件\"></textarea>\n        </div>\n        <button onclick=\"encodeBase64()\">编码为 Base64</button>\n        <button onclick=\"decodeBase64()\">解码为文本</button>\n        <div class=\"output\" id=\"base64-output\"></div>\n      </div>\n    </section>\n\n    <section class=\"tab-content\" id=\"timestamp\">\n      <div class=\"tool-card\">\n        <h2 class=\"tool-title\">时间戳转换</h2>\n        <p class=\"tool-description\">秒级/毫秒级 ↔ 本地时区日期互转；支持 RFC3339、ISO8601 等格式</p>\n        <div class=\"input-group\">\n          <input type=\"text\" id=\"timestamp-input\" placeholder=\"1717027200000 → 2024-05-30 00:00:00 (CST)\" />\n        </div>\n        <button onclick=\"convertTimestamp()\">转换时间戳</button>\n        <div class=\"output\" id=\"timestamp-output\"></div>\n      </div>\n    </section>\n\n    <section class=\"tab-content\" id=\"regex\">\n      <div class=\"tool-card\">\n        <h2 class=\"tool-title\">正则测试器</h2>\n        <p class=\"tool-description\">实时匹配高亮、分组捕获可视化、常用模板一键插入</p>\n        <div class=\"input-group\">\n          <input type=\"text\" id=\"regex-pattern\" placeholder=\"输入正则：^\\\\d{3}-\\\\d{2}-\\\\d{4}$\" />\n          <textarea id=\"regex-text\" placeholder=\"测试文本：123-45-6789 → ✅ 匹配\"></textarea>\n        </div>\n        <button onclick=\"testRegex()\">测试正则</button>\n        <div class=\"output\" id=\"regex-output\"></div>\n      </div>\n    </section>\n\n    <section class=\"tab-content\" id=\"color\">\n      <div class=\"tool-card\">\n        <h2 class=\"tool-title\">颜色选择器</h2>\n        <p class=\"tool-description\">HEX/RGB/HSL/RGBA 实时互转；亮度对比度检测（WCAG AA/AAA）</p>\n        <div class=\"input-group\">\n          <input type=\"text\" id=\"color-input\" placeholder=\"#4ec9b0 → rgb(78, 201, 176) → hsl(167°, 52%, 55%)\" />\n        </div>\n        <button onclick=\"convertColor()\">转换颜色</button>\n        <div class=\"output\" id=\"color-output\"></div>\n      </div>\n    </section>\n  </main>\n\n  <footer>\n    <p>DevKit Terminal —— 专为开发者打造的零依赖终端工具箱 · 纯前端 · 无网络请求 · 数据永不离开浏览器 · 暗色护眼模式默认启用</p>\n  </footer>\n\n  <script>\n    // Tab切换功能\n    document.querySelectorAll(\'.tab-button\').forEach(button => {\n      button.addEventListener(\'click\', () => {\n        const tab = button.getAttribute(\'data-tab\');\n        document.querySelectorAll(\'.tab-content\').forEach(content => {\n          content.classList.remove(\'active\');\n        });\n        document.querySelectorAll(\'.tab-button\').forEach(btn => {\n          btn.classList.remove(\'active\');\n        });\n        document.getElementById(tab).classList.add(\'active\');\n        button.classList.add(\'active\');\n      });\n    });\n\n    // JSON格式化\n    function formatJson() {\n      const input = document.getElementById(\'json-input\').value;\n      try {\n        const parsed = JSON.parse(input);\n        const formatted = JSON.stringify(parsed, null, 2);\n        document.getElementById(\'json-output\').textContent = formatted;\n      } catch (e) {\n        document.getElementById(\'json-output\').textContent = `错误: ${e.message}`;\n      }\n    }\n\n    // Base64编码\n    function encodeBase64() {\n      const input = document.getElementById(\'base64-input\').value;\n      const encoded = btoa(input);\n      document.getElementById(\'base64-output\').textContent = encoded;\n    }\n\n    // Base64解码\n    function decodeBase64() {\n      const input = document.getElementById(\'base64-input\').value;\n      try {\n        const decoded = atob(input);\n        document.getElementById(\'base64-output\').textContent = decoded;\n      } catch (e) {\n        document.getElementById(\'base64-output\').textContent = `错误: ${e.message}`;\n      }\n    }\n\n    // 时间戳转换\n    function convertTimestamp() {\n      const input = document.getElementById(\'timestamp-input\').value;\n      if (!input) return;\n      const timestamp = parseInt(input);\n      if (isNaN(timestamp)) {\n        document.getElementById(\'timestamp-output\').textContent = \'请输入有效的数字时间戳\';\n        return;\n      }\n      const date = new Date(timestamp);\n      const options = { \n        year: \'numeric\', \n        month: \'2-digit\', \n        day: \'2-digit\', \n        hour: \'2-digit\', \n        minute: \'2-digit\', \n        second: \'2-digit\',\n        timeZoneName: \'short\'\n      };\n      const formattedDate = date.toLocaleString(\'zh-CN\', options);\n      document.getElementById(\'timestamp-output\').textContent = `${timestamp} → ${formattedDate}`;\n    }\n\n    // 正则测试\n    function testRegex() {\n      const pattern = document.getElementById(\'regex-pattern\').value;\n      const text = document.getElementById(\'regex-text\').value;\n      if (!pattern || !text) {\n        document.getElementById(\'regex-output\').textContent = \'请输入正则表达式和测试文本\';\n        return;\n      }\n      try {\n        const regex = new RegExp(pattern);\n        const match = regex.exec(text);\n        if (match) {\n          document.getElementById(\'regex-output\').textContent = `匹配成功: ${match[0]}`;\n        } else {\n          document.getElementById(\'regex-output\').textContent = \'未找到匹配项\';\n        }\n      } catch (e) {\n        document.getElementById(\'regex-output\').textContent = `错误: ${e.message}`;\n      }\n    }\n\n    // 颜色转换\n    function convertColor() {\n      const input = document.getElementById(\'color-input\').value;\n      const color = input.trim();\n      if (!color) {\n        document.getElementById(\'color-output\').textContent = \'请输入颜色值（如 #4ec9b0 或 rgb(78, 201, 176)）\';\n        return;\n      }\n      let result = \'\';\n      try {\n        // HEX to RGB\n        if (/^#([A-Fa-f0-9]{6})$/.test(color)) {\n          const hex = color.slice(1);\n          const r = parseInt(hex.substring(0, 2), 16);\n          const g = parseInt(hex.substring(2, 4), 16);\n          const b = parseInt(hex.substring(4, 6), 16);\n          result += `HEX: ${color} → RGB: rgb(${r}, ${g}, ${b})\\n`;\n        }\n        // RGB to HEX\n        else if (/^rgb\\((\\d{1,3}),\\s*(\\d{1,3}),\\s*(\\d{1,3})\\)$/.test(color)) {\n          const [r, g, b] = color.match(/\\d+/g).map(Number);\n          const hex = ((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1).toUpperCase();\n          result += `RGB: ${color} → HEX: #${hex}\\n`;\n        }\n        // HSL to RGB\n        else if (/^hsl\\((\\d+),\\s*(\\d+)%,\\s*(\\d+)%\\)$/.test(color)) {\n          const [h, s, l] = color.match(/\\d+/g).map(Number);\n          const c = (1 - Math.abs(2 * l / 100 - 1)) * s / 100;\n          const x = c * (1 - Math.abs((h / 60) % 2 - 1));\n          const m = l / 100 - c / 2;\n          let r, g, b;\n          if (h >= 0 && h < 60) { r = c; g = x; b = 0; }\n          else if (h >= 60 && h < 120) { r = x; g = c; b = 0; }\n          else if (h >= 120 && h < 180) { r = 0; g = c; b = x; }\n          else if (h >= 180 && h < 240) { r = 0; g = x; b = c; }\n          else if (h >= 240 && h < 300) { r = x; g = 0; b = c; }\n          else { r = c; g = 0; b = x; }\n          result += `HSL: ${color} → RGB: rgb(${Math.round((r + m) * 255)}, ${Math.round((g + m) * 255)}, ${Math.round((b + m) * 255)})\\n`;\n        }\n        // RGBA to HEX\n        else if (/^rgba\\((\\d{1,3}),\\s*(\\d{1,3}),\\s*(\\d{1,3}),\\s*([0-1](\\.\\d+)?)\\)$/.test(color)) {\n          const [r, g, b, a] = color.match(